export class AnthropicError extends Error {}

export class APIError<
  TStatus extends number | undefined = number | undefined,
  THeaders extends Headers | undefined = Headers | undefined,
  TError extends Object | undefined = Object | undefined,
> extends AnthropicError {
  readonly status: TStatus;
  readonly headers: THeaders;
  readonly error: TError;
}

export class BadRequestError extends APIError<400, Headers, Object> {}
export class AuthenticationError extends APIError<401, Headers, Object> {}
export class RateLimitError extends APIError<429, Headers, Object> {}
